  next()
})

jobEntity.intercept("update.provider_id", async (req, res, next) => {
  const job = await jobService.findById(req.params.id)
  if (job?.provider_id && job.provider_id !== req.user.uuid) {
    return res.status(403).json({ message: "Cannot reassign a job you do not own" })
  }
  next()
})

profileEntity.intercept("update.personal_information", (req, res, next) => {
  // fires for PATCH /:id with body { personal_information: ... }
  // also fires for PATCH /:id/nested with body.field = "personal_information.email"
  if (req.user.uuid !== req.params.id) {
    return res.status(403).json({ message: "Cannot edit another profile" })
  }
  next()
})

