typescript.example:
import { MetaEntity, BaseEntityDocument } from "@ubyjerome/meta-manager";
import Joi from "joi";

interface BookDocument extends BaseEntityDocument {
  isbn: string;
  pageCount: number;
  libraryId: string;
}

const booksEntity = new MetaEntity<BookDocument>("books", {
  createSchema: {
    title_name:  Joi.string().required(),
    isbn:        Joi.string().optional(),
    pageCount:   Joi.number().min(0).optional(),
    libraryId:   Joi.string().required()
  }
});

// service is fully typed as IMetaService<BookDocument>
const book = await booksEntity.service.findById("uuid");
// book is BookDocument | null

// trigger is typed - IDE suggests valid event paths
booksEntity.trigger(["update.isbn"], (whatWas, whatIs, book) => {
  // whatWas: Partial<BookDocument>  (non-null guaranteed)
  // whatIs:  Partial<BookDocument>  (non-null guaranteed)
  // book:    BookDocument
});

