fieldpolicy.example:
const profileEntity = new MetaEntity("profiles", {
  fieldPolicy: {
    airbnb_access_token: {
      // Never expose this field to non-admins
      read: (req) => req.user?.isAdmin === true
    },
    is_vetted: {
      // Only admins can set this field; throw if non-admin tries
      write: (req) => req.user?.isAdmin === true,
      strict: true
    },
    subscription_tier: {
      // Silently drop if non-admin tries to set it
      write: (req) => req.user?.role === "admin"
    }
  }
})

// For non-admin request:
// airbnb_access_token is stripped from every response
// Attempting to write is_vetted throws 403
// Attempting to write subscription_tier silently ignores the field

