// Entity definition
const jobEntity = new MetaEntity("jobs", {
  fieldPolicy: {
    internal_notes: { read: (req) => req.user?.isAdmin === true }
  },
  scopedService: { userField: "user", userIdField: "uuid" }
})

// In your Express route handler
app.post("/jobs", authMiddleware, async (req, res) => {
  const service = jobEntity.serviceFor(req)
  // created_by and added_by auto-filled from req.user.uuid
  // internal_notes stripped from response for non-admin
  const job = await service.create(req.body)
  res.json(job)
})

// On update
app.patch("/jobs/:id", authMiddleware, async (req, res) => {
  const service = jobEntity.serviceFor(req)
  // updated_by auto-filled
  const job = await service.update(req.params.id, req.body)
  res.json(job)
})

