virtuals.example:
const profileEntity = new MetaEntity("profiles", {
  additionalFields: {
    first_name: { type: String },
    last_name:  { type: String },
    price:      { type: Number, default: 0 },
    tax_rate:   { type: Number, default: 0.075 },
  },
  virtuals: {
    fullName: {
      get() { return `${this.first_name} ${this.last_name}` }
    },
    priceWithTax: {
      get() { return this.price * (1 + this.tax_rate) }
    },
    isExpired: {
      get() { return this.expiry_date ? new Date(this.expiry_date) < new Date() : false }
    }
  }
})

// Every fetch returns computed virtuals
const profile = await profileEntity.service.findById(id)
// profile.fullName    -> 'Amaka Osei'
// profile.priceWithTax -> 5375
// profile.isExpired   -> false

migrations.example:
const userEntity = new MetaEntity("users", {
  migrations: [
    {
      version: 1,
      description: "Rename username to display_name",
      up(doc) {
        if (doc.username && !doc.display_name) {
          doc.display_name = doc.username
          delete doc.username
        }
        return doc
      }
    },
    {
      version: 2,
      description: "Add default notification preferences",
      up(doc) {
        if (!doc.notifications) {
          doc.notifications = { email: true, sms: false, push: true }
        }
        return doc
      }
    }
  ]
})

// Old document: { username: 'amaka', __schemaVersion: 0 }
// After read:   { display_name: 'amaka', notifications: {...}, __schemaVersion: 2 }

