// Verify the signature in your webhook receiver
const crypto = require('crypto')
app.post('/webhook', (req, res) => {
  const sig = req.headers['x-metamanager-signature']
  const expected = 'sha256=' + crypto
    .createHmac('sha256', process.env.WEBHOOK_SECRET)
    .update(JSON.stringify(req.body))
    .digest('hex')
  if (sig !== expected) return res.status(401).end()
  // process event
  res.status(200).end()
})

serialiser.example:
const profileEntity = new MetaEntity("profiles", {
  serialiser: {
    transform(doc, req) {
      // Strip internal fields from HTTP responses
      const { __schemaVersion, __v, internal_token, ...rest } = doc

      // Add computed presentation fields
      return {
        ...rest,
        displayName: [doc.first_name, doc.last_name].filter(Boolean).join(' '),
        isVerified: Boolean(doc.id_verified && doc.is_vetted),
      }
    }
  }
})

// Async serialiser with a database lookup
const bookEntity = new MetaEntity("books", {
  serialiser: {
    async transform(doc, req) {
      const readCount = await analyticsService.getReadCount(doc.uuid)
      return { ...doc, readCount, _internalId: undefined }
    }
  }
})
